const results = $json.results || [];
const restaurants = results.map(place => ({
  place_id: place.place_id,
  name: place.name,
  address: place.vicinity,
  rating: place.rating || 0,
  review_count: place.user_ratings_total || 0,
  types: place.types?.join(', ') || '',
  lat: place.geometry?.location?.lat,
  lng: place.geometry?.location?.lng
}));
return restaurants.map(r => ({ json: r }));

const detail = $json.result || {};
const restaurant = $input.first().json;
return [{ json: {
  ...restaurant,
  website: detail.website || '',
  phone: detail.formatted_phone_number || ''
} }];

const restaurant = $input.first().json;
const html = ($json.data || '').toLowerCase();

const hasOrderOnline = /order.*online|online.*order|order.*now/i.test(html);
const hasDoordash = /doordash|door dash/i.test(html);
const hasUbereats = /uber\s*eats|ubereats/i.test(html);
const hasGrubhub = /grubhub|grub hub/i.test(html);
const hasSquare = /square|squareup/i.test(html);
const hasToast = /toasttab|toast/i.test(html);
const hasChownow = /chownow|chow now/i.test(html);

let score = 0;
let reasons = [];

if (restaurant.website) { score += 1; reasons.push('has_website'); }
if (!hasOrderOnline) { score += 2; reasons.push('no_online_ordering'); }
if (hasDoordash || hasUbereats || hasGrubhub) { score += 1; reasons.push('on_third_party'); }
if (restaurant.rating >= 3.5) { score += 1; reasons.push('good_rating'); }
if (restaurant.phone) { score += 1; reasons.push('has_phone'); }

let category = 'Skip';
if (score >= 4) category = 'Qualified';
else if (score >= 2) category = 'Research';

return [{ json: {
  ...restaurant,
  has_order_online: hasOrderOnline,
  has_doordash: hasDoordash,
  has_ubereats: hasUbereats,
  has_grubhub: hasGrubhub,
  has_square: hasSquare,
  has_toast: hasToast,
  has_chownow: hasChownow,
  score,
  score_reasons: reasons,
  category,
  stage: 'New',
  owner: 'Green',
  created_date: new Date().toISOString(),
  source: 'n8n_scraper'
} }];

const sqlite3 = require("sqlite3");
const DB_PATH = process.env.CRM_DB_PATH || '/home/node/sol-workspace/green-systems-crm.db';
const lead = $input.first().json;

return new Promise((resolve, reject) => {
  const db = new sqlite3.Database(DB_PATH);
  const query = `
    INSERT INTO leads (
      place_id, name, address, phone, website, rating, review_count,
      category, score, stage, owner, created_date, source,
      has_order_online, has_doordash, has_ubereats, has_grubhub,
      has_square, has_toast, has_chownow
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(place_id) DO UPDATE SET
      name = excluded.name,
      address = excluded.address,
      phone = excluded.phone,
      website = excluded.website,
      rating = excluded.rating,
      review_count = excluded.review_count,
      category = excluded.category,
      score = excluded.score,
      has_order_online = excluded.has_order_online,
      has_doordash = excluded.has_doordash,
      has_ubereats = excluded.has_ubereats,
      has_grubhub = excluded.has_grubhub,
      has_square = excluded.has_square,
      has_toast = excluded.has_toast,
      has_chownow = excluded.has_chownow
  `;
  const values = [
    lead.place_id, lead.name, lead.address, lead.phone, lead.website,
    lead.rating, lead.review_count, lead.category, lead.score,
    lead.stage, lead.owner, lead.created_date, lead.source,
    lead.has_order_online ? 1 : 0, lead.has_doordash ? 1 : 0,
    lead.has_ubereats ? 1 : 0, lead.has_grubhub ? 1 : 0,
    lead.has_square ? 1 : 0, lead.has_toast ? 1 : 0,
    lead.has_chownow ? 1 : 0
  ];
  db.run(query, values, function(err) {
    db.close();
    if (err) {
      resolve([{ json: { error: err.message, ...lead } }]);
    } else {
      resolve([{ json: { ...lead, db_status: 'saved', db_changes: this.changes } }]);
    }
  });
});

const lead = $input.first().json;

return [{
  json: {
    subject: `🎯 New Qualified Lead: ${lead.name}`,
    text: `A new qualified restaurant lead was found:

🏢 ${lead.name}
📍 ${lead.address || 'N/A'}
📞 ${lead.phone || 'N/A'}
🌐 ${lead.website || 'N/A'}
⭐ ${lead.rating}/5 (${lead.review_count} reviews)

📊 Score: ${lead.score}/5
🏷️  Category: ${lead.category}

Website Signals:
- Online Ordering: ${lead.has_order_online ? 'Yes' : 'No'}
- DoorDash: ${lead.has_doordash ? 'Yes' : 'No'}
- UberEats: ${lead.has_ubereats ? 'Yes' : 'No'}
- Grubhub: ${lead.has_grubhub ? 'Yes' : 'No'}

Review in CRM: sqlite3 ~/.openclaw/workspaces/sol/green-systems-crm.db`
  }
}];
